def run_command(command, description, capture_output=False):
    """Run a shell command and handle errors."""
    print(f"\n{'='*60}")
    print(f"STEP: {description}")
    print(f"CMD:  {' '.join(command) if isinstance(command, list) else command}")
    print(f"{'='*60}")

    try:
        result = subprocess.run(
            command,
            check=True,
            capture_output=capture_output,
            text=True,
            timeout=300,
        )
        print(f"✅ {description} - SUCCESS")
        return result
    except subprocess.CalledProcessError as e:
        print(f"❌ {description} - FAILED (exit code {e.returncode})")
        if e.stdout:
            print(f"STDOUT: {e.stdout}")
        if e.stderr:
            print(f"STDERR: {e.stderr}")
        sys.exit(1)
    except subprocess.TimeoutExpired:
        print(f"❌ {description} - TIMED OUT")
        sys.exit(1)


def check_requirements_file():
    """Verify requirements.txt exists and is not empty."""
    print("\n🔍 Checking requirements file...")
    req_path = Path(REQUIREMENTS_FILE)

    if not req_path.exists():
        print(f"❌ {REQUIREMENTS_FILE} not found!")
        sys.exit(1)

    if req_path.stat().st_size == 0:
        print(f"❌ {REQUIREMENTS_FILE} is empty!")
        sys.exit(1)

    print(f"✅ {REQUIREMENTS_FILE} found ({req_path.stat().st_size} bytes)")
    return req_path


def parse_requirement_line(line):
    """Parse a single requirement line into package name and version info."""
    line = line.strip()
    if not line or line.startswith("#") or line.startswith("-"):
        return None, None, None

    # Handle various version specifiers
    for op in ["==", ">=", "<=", "!=", "~=", ">", "<"]:
        if op in line:
            parts = line.split(op, 1)
            pkg_name = parts[0].strip().lower()
            version = parts[1].strip().split(",")[0].strip()
            return pkg_name, op, version

    return line.strip().lower(), None, None


def parse_version(version_str):
    """Parse a version string into a tuple of integers for comparison."""
    try:
        parts = []
        for part in version_str.split("."):
            # Handle versions like "1.2.3a1" by stripping non-numeric suffixes
            numeric = ""
            for ch in part:
                if ch.isdigit():
                    numeric += ch
                else:
                    break
            parts.append(int(numeric) if numeric else 0)
        return tuple(parts)
    except (ValueError, AttributeError):
        return (0,)


def version_less_than(v1, v2):
    """Check if version v1 is less than v2."""
    t1 = parse_version(v1)
    t2 = parse_version(v2)
    # Pad to same length
    max_len = max(len(t1), len(t2))
    t1 = t1 + (0,) * (max_len - len(t1))
    t2 = t2 + (0,) * (max_len - len(t2))
    return t1 < t2


def check_outdated_dependencies(req_path):
    """Check for outdated or vulnerable dependencies and prevent their use."""
    print("\n🔍 Checking for outdated/vulnerable dependencies...")
    issues = []
    warnings = []
    unpinned = []

    with open(req_path, "r") as f:
        lines = f.readlines()

    for line_num, line in enumerate(lines, 1):
        pkg_name, op, version = parse_requirement_line(line)
        if pkg_name is None:
            continue

        # Check for unpinned dependencies (no version specified)
        if op is None:
            unpinned.append((line_num, pkg_name))
            issues.append(
                f"  Line {line_num}: '{pkg_name}' has no version pin. "
                f"Pin with '==' for reproducible builds."
            )
            continue

        # Warn about non-exact pins in production
        if op != "==":
            warnings.append(
                f"  Line {line_num}: '{pkg_name}{op}{version}' uses '{op}' instead of '=='. "
                f"Consider exact pinning for production."
            )

        # Check against known vulnerable versions
        if pkg_name in KNOWN_VULNERABLE_PACKAGES and version:
            min_safe_version = KNOWN_VULNERABLE_PACKAGES[pkg_name]
            if version_less_than(version, min_safe_version):
                issues.append(
                    f"  Line {line_num}: '{pkg_name}=={version}' is below minimum safe "
                    f"version {min_safe_version}. Known vulnerabilities exist!"
                )

    # Check for dependency freshness using pip's outdated check
    print("  Checking installed package freshness...")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
            capture_output=True,
            text=True,
            timeout=120,
        )
        if result.returncode == 0 and result.stdout.strip():
            outdated_packages = json.loads(result.stdout)
            if outdated_packages:
                print(f"  ⚠️  {len(outdated_packages)} outdated package(s) detected:")
                for pkg in outdated_packages:
                    pkg_lower = pkg.get("name", "").lower()
                    current = pkg.get("version", "unknown")
                    latest = pkg.get("latest_version", "unknown")
                    warnings.append(
                        f"  '{pkg_lower}': installed={current}, latest={latest}"
                    )
    except (subprocess.TimeoutExpired, json.JSONDecodeError, FileNotFoundError):
        warnings.append("  Could not check for outdated packages via pip.")

    # Report warnings
    if warnings:
        print(f"\n⚠️  Dependency warnings ({len(warnings)}):")
        for w in warnings:
            print(f"    {w}")

    # Report and fail on critical issues
    if issues:
        print(f"\n❌ Critical dependency issues found ({len(issues)}):")
        for issue in issues:
            print(f"    {issue}")
        print(
            "\n❌ DEPLOYMENT BLOCKED: Fix dependency issues before deploying to production."
        )
        print("   - Pin all dependencies with exact versions (==)")
        print("   - Update packages with known vulnerabilities")
        print("   - Run 'pip-audit' for comprehensive vulnerability scanning")
        sys.exit(1)

    print("✅ Dependency checks passed")


def compute_requirements_hash(req_path):
    """Compute hash of requirements file for cache invalidation."""
    hasher = hashlib.sha256()
    with open(req_path, "rb") as f:
        hasher.update(f.read())
    return hasher.hexdigest()[:12]


def install_dependencies(req_path):
    """Install project dependencies from requirements.txt."""
    print("\n📦 Installing dependencies...")

    # Upgrade pip first
    run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )

    # Install dependencies with hash checking if available
    run_command(
        [
            sys.executable,
            "-m",
            "pip",
            "install",
            "-r",
            str(req_path),
            "--no-cache-dir",
            "--disable-pip-version-check",
        ],
        "Installing project dependencies",
    )

    # Verify installation
    run_command(
        [sys.executable, "-m", "pip", "check"],
        "Verifying dependency compatibility",
    )

    req_hash = compute_requirements_hash(req_path)
    print(f"📋 Requirements hash: {req_hash}")


