def clean_build_artifacts():
    """Clean previous build artifacts."""
    print("\n🧹 Cleaning previous build artifacts...")

    for dir_name in [DIST_DIR, BUILD_DIR, f"{PACKAGE_NAME}.egg-info"]:
        dir_path = Path(dir_name)
        if dir_path.exists():
            shutil.rmtree(dir_path)
            print(f"  Removed {dir_name}/")

    # Clean __pycache__ directories
    for pycache in Path(".").rglob("__pycache__"):
        shutil.rmtree(pycache)

    print("✅ Clean complete")


def package_application():
    """Package the application for deployment."""
    print("\n📦 Packaging application for deployment...")

    clean_build_artifacts()

    # Create dist directory
    dist_path = Path(DIST_DIR)
    dist_path.mkdir(exist_ok=True)

    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")

    # Check if setup.py or pyproject.toml exists for proper packaging
    if Path("setup.py").exists() or Path("pyproject.toml").exists():
        run_command(
            [sys.executable, "-m", "pip", "install", "build"],
            "Installing build tool",
        )
        run_command(
            [sys.executable, "-m", "build"],
            "Building distribution package",
        )
    else:
        # Fallback: create a deployment archive
        archive_name = f"{PACKAGE_NAME}_{timestamp}"
        print(f"  Creating deployment archive: {archive_name}.tar.gz")

        # Collect files to package (exclude common non-deployment files)
        exclude_patterns = {
            ".git",
            ".gitignore",
            "__pycache__",
            ".pytest_cache",
            ".mypy_cache",
            ".tox",
            ".venv",
            "venv",
            "env",
            ".env",
            "node_modules",
            DIST_DIR,
            BUILD_DIR,
            ".eggs",
        }

        import tarfile

        archive_path = dist_path / f"{archive_name}.tar.gz"
        with tarfile.open(archive_path, "w:gz") as tar:
            for item in Path(".").iterdir():
                if item.name not in exclude_patterns and not item.name.startswith("."):
                    tar.add(item, arcname=f"{archive_name}/{item}")

        print(f"  Archive size: {archive_path.stat().st_size / 1024:.1f} KB")

    # Generate deployment manifest
    manifest = {
        "package": PACKAGE_NAME,
        "timestamp": timestamp,
        "python_version": sys.version,
        "requirements_hash": compute_requirements_hash(Path(REQUIREMENTS_FILE)),
        "files": [str(f) for f in dist_path.iterdir()],
    }

    manifest_path = dist_path / "deployment_manifest.json"
    with open(manifest_path, "w") as f:
        json.dump(manifest, f, indent=2)

    print(f"✅ Package created in {DIST_DIR}/")
    print(f"📋 Manifest: {manifest_path}")

    return dist_path


def generate_deployment_report(start_time):
    """Generate a summary report of the deployment build."""
    elapsed = time.time() - start_time
    print(f"\n{'='*60}")
    print("📊 DEPLOYMENT BUILD REPORT")
    print(f"{'='*60}")
    print(f"  Status:     ✅ SUCCESS")
    print(f"  Duration:   {elapsed:.1f}s")
    print(f"  Python:     {sys.version.split()[0]}")
    print(f"  Platform:   {sys.platform}")
    print(f"  Timestamp:  {datetime.now(timezone.utc).isoformat()}")
    print(f"  Output:     {DIST_DIR}/")

    if Path(DIST_DIR).exists():
        files = list(Path(DIST_DIR).iterdir())
        total_size = sum(f.stat().st_size for f in files if f.is_file())
        print(f"  Artifacts:  {len(files)} file(s), {total_size / 1024:.1f} KB total")

    print(f"{'='*60}")
    print("🚀 Ready for deployment!")


def main():
    """Main deployment pipeline."""
    start_time = time.time()

    print("🚀 Starting Deployment Pipeline")
    print(f"   Python: {sys.version}")
